using SolidWorks.Interop.sldworks;

namespace SwAutomation;

public static class Project1
{
    public static void Run(string outFolder, Part part, Assembly assembly)
    {
        if (string.IsNullOrWhiteSpace(outFolder))
            throw new System.ArgumentException("Output folder is required.", nameof(outFolder));

        // 1) Create parts (names are generated by PDM save flow)
        string skeleton = part.CreateSkeleton(
            sideOffset: 500.0,
            groundOffset: -250.0,
            outFolder: outFolder,
            closeAfterCreate: true,
            SaveToPdm: true);

        // 2) Create assemblies (capture real vaulted file names)
        string rotor = assembly.CreateAssembly(outFolder, "RotorComplete.SLDASM", closeAfterCreate: true, SaveToPdm: true);
        string stator = assembly.CreateAssembly(outFolder, "StatorComplete.SLDASM", closeAfterCreate: true, SaveToPdm: true);
        string housing = assembly.CreateAssembly(outFolder, "HousingMachined.SLDASM", closeAfterCreate: true, SaveToPdm: true);
        string machine = assembly.CreateAssembly(outFolder, "MachineAssembly.SLDASM", closeAfterCreate: false, SaveToPdm: true);

        // 3) Insert and mate components into the open machine assembly
        Component2 inserted = assembly.InsertComponentToOpenAssembly(skeleton);
        assembly.mate_plans(inserted);

        inserted = assembly.InsertComponentToOpenAssembly(rotor);
        assembly.mate_plans(inserted);

        inserted = assembly.InsertComponentToOpenAssembly(stator);
        assembly.mate_plans(inserted);

        inserted = assembly.InsertComponentToOpenAssembly(housing);
        assembly.mate_plans(inserted);

        System.Console.WriteLine($"Macro completed. Machine assembly: {machine}");
    }
        public static void Run2(string outFolder, Part part, Assembly assembly)
    {
        if (string.IsNullOrWhiteSpace(outFolder))
            throw new System.ArgumentException("Output folder is required.", nameof(outFolder));

        // 1) Create parts (names are generated by PDM save flow)
        string skeleton = part.CreateSkeleton(
            sideOffset: 2000.0,
            groundOffset: -500.0,
            outFolder: outFolder,
            closeAfterCreate: true,
            SaveToPdm: false);

        string statorsheet = part.Create_stator_sheet(outFolder, true, SaveToPdm: false);
        string shaft = part.Create_shaft(outFolder, true, SaveToPdm: false);
        string machine = assembly.CreateAssembly(outFolder, "MachineAssembly.SLDASM", closeAfterCreate: false, SaveToPdm: false);

        Component2 inserted_skeleton = assembly.InsertComponentToOpenAssembly(skeleton);
        assembly.mate_plans(inserted_skeleton);
        Component2 inserted_statorsheet = assembly.InsertComponentToOpenAssembly(statorsheet);
        Component2 inserted_shaft = assembly.InsertComponentToOpenAssembly(shaft);
        assembly.ApplyCoincedentMate(inserted_skeleton, "X-Achse", inserted_statorsheet, "Z-Achse");
        assembly.ApplyCoincedentMate(inserted_skeleton, "Ebene rechts", inserted_statorsheet, "Ebene vorne");
        assembly.ApplyCoincedentMate(inserted_skeleton, "Ebene vorne", inserted_statorsheet, "Ebene rechts");
        assembly.ApplyCoincedentMate(inserted_skeleton, "X-Achse", inserted_shaft, "Z-Achse");
        System.Console.WriteLine($"Macro completed. Machine assembly: {machine}");
    }
